import{_ as o,o as e,c as t,a2 as r}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"G05: 營收模式與收費策略 - 經營審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/6442_光聖/20260504/G05_營收模式與收費策略.md","filePath":"審計報告庫/經營審計/6442_光聖/20260504/G05_營收模式與收費策略.md"}'),l={name:"審計報告庫/經營審計/6442_光聖/20260504/G05_營收模式與收費策略.md"};function i(n,a,s,h,_,d){return e(),t("div",null,[...a[0]||(a[0]=[r('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的經營洞見。</p><h1 id="g05-營收模式與收費策略-經營審計專家報告" tabindex="-1">G05: 營收模式與收費策略 - 經營審計專家報告 <a class="header-anchor" href="#g05-營收模式與收費策略-經營審計專家報告" aria-label="Permalink to &quot;G05: 營收模式與收費策略 - 經營審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>公司的主要營收模式與收費策略為何？其獲利的穩定性與可預測性如何？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>營收模式為單客高集中JDM——合約按訂單出貨無經常性收入。月變動平均26.5%，預測性極低。2025年營收NT$105.3億但結構脆弱。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>B (持平)</strong>：營收規模成長但結構風險突出。經常性收入佔比近0%；月營收平均MoM變動26.5%（最大145.4%）；Google貢獻約90%。月營收從2023年4月2.05億到2024年12月13.6億再到2025年2月5.1億，暴起暴落反映Google採購節奏不規律，非公司能見度差。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p>營收100%來自產品銷售（光通訊80%+RF 20%），無服務費/權利金/訂閱收入。JDM模式賦予高議價力（GPM 57.74%），但排他性綁定——一旦成Google共同設計夥伴須投入大量工程資源，無法同時接其他CSP訂單。</p><p>毛利率從2023年~31%升至2025年57.74%，顯示AI需求爆發期強價格傳導力。但此價格力來自供不應求非結構性定價權——2026年毛利率目標已從57.74%降至&gt;50%，降價壓力已浮現。成本結構中光纖原料為主要變動成本（美日供應商NDA未揭露）。</p><p>月營收平均|MoM|變動26.5%（2024/12 +145.4%極端），標準差NT$3億。2026年訂單能見度至Q3，但Google以PO滾動式下單無正式合約保障。2023年EPS 0.05元的經驗證明只要Google一季不拉貨獲利可能歸零。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>訂單週期不可控壓力</strong>：Google以PO滾動式下單無合約保障，2023年EPS 0.05元證明只要一季不拉貨獲利歸零。月MoM變動26.5%使季度預測形同猜謎。</li><li><strong>降價壓力持續侵蝕</strong>：毛利率目標從57.74%降至&gt;50%，Google採購量擴大後的議價僅是開始。</li><li><strong>零經常性收入結構挑戰</strong>：100%產品銷售收入無訂閱/維護費，經濟下行時無緩衝。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>JDM模式高附加價值</strong>：非純EMS代工，參與定義規格使單價利潤空間遠高同業。</li><li><strong>營收成長動能強勁</strong>：2025年NT$105.3億較2024倍增，即使降價絕對毛利仍持續增長。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>FinMind</strong>：TaiwanStockMonthRevenue (2023/04-2026/03)，MoM變動率計算</li><li><strong>web_fetch</strong>：富果法說會備忘錄(2026/3/12)確認營收模式與能見度</li><li><strong>web_search</strong>：毛利率數據、法說會Q&amp;A關於訂單模式</li><li><strong>原始數據</strong>：stock_id=6442, monthly revenue volatility analysis</li></ul>',19)])])}const u=o(l,[["render",i]]);export{g as __pageData,u as default};
